module gray_to_binary(
    input  [3:0] gray_in,
    output [3:0] obf_binary_out
);

    assign obf_binary_out[3] = gray_in[3];
    assign obf_binary_out[2] = gray_in[3] ^ gray_in[2];
    assign obf_binary_out[1] = obf_binary_out[2] ^ gray_in[1];
    assign obf_binary_out[0] = obf_binary_out[1] ^ gray_in[0];

endmodule
